--
-- Table structure for table `cvi_carousel`
--

CREATE TABLE `cvi_carousel` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `component` varchar(128) NOT NULL,
  `payload_type` varchar(64) NOT NULL,
  `payload` longtext NOT NULL,
  `source_actor` varchar(128) DEFAULT NULL,
  `source_system` varchar(128) DEFAULT NULL,
  `signature` varchar(255) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL DEFAULT current_timestamp(6),
  `processed` tinyint(1) NOT NULL DEFAULT 0,
  `processed_at` datetime(6) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `igm_attestations`
--

CREATE TABLE `igm_attestations` (
  `id` bigint(20) NOT NULL,
  `attested_ts` datetime(6) NOT NULL,
  `rule_id` varchar(64) NOT NULL,
  `rule_scope` varchar(64) DEFAULT NULL,
  `rule_state` varchar(32) DEFAULT NULL,
  `rule_effect` varchar(64) DEFAULT NULL,
  `worker` varchar(64) DEFAULT NULL,
  `stage` varchar(64) DEFAULT NULL,
  `series_id` int(11) DEFAULT NULL,
  `payload` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=MyISAM DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

-- --------------------------------------------------------

--
-- Table structure for table `igm_attestation_ledger`
--

CREATE TABLE `igm_attestation_ledger` (
  `attestation_id` bigint(20) NOT NULL,
  `evaluation_id` bigint(20) NOT NULL,
  `attested_by` enum('system','human','ai') NOT NULL,
