INSERT INTO `igm_candidate_rules` (`candidate_id`, `inferred_rule`, `source_events`, `confidence_score`, `status`, `created_at`) VALUES
(1, 'Truth Before Convenience: System truth, data integrity, provenance, and governance constraints must never be compromised for convenience, speed, customer experience, or perceived completeness.', '{\"document\": \"TOGAF Preliminary Phase - Architecture Principles (Principle 1)\"}', 0.95, '', '2026-01-29 22:38:45'),
(2, 'Database as Authority: The database is the authoritative system of record for all operational, architectural, and governance truth. No component (including AI) may bypass database constraints.', '{\"document\": \"TOGAF Preliminary Phase - Architecture Principles (Principle 2)\"}', 0.95, '', '2026-01-29 22:38:46'),
(3, 'Automation First: All operational processes must be automatable, schedulable, and repeatable. Manual processes do not scale and cannot be governed reliably.', '{\"document\": \"TOGAF Preliminary Phase - Architecture Principles (Principle 3)\"}', 0.90, '', '2026-01-29 22:38:46'),
(4, 'Governance Over Optimization: Architectural governance takes precedence over performance optimization, cost reduction, and implementation convenience.', '{\"document\": \"TOGAF Preliminary Phase - Architecture Principles (Principle 4)\"}', 0.95, '', '2026-01-29 22:38:47'),
(5, 'AI Without Agency: AI systems may observe, analyze, explain, and propose — but may not decide, enforce, or act autonomously. AI may never write directly to production databases or promote rules to canon.', '{\"document\": \"TOGAF Preliminary Phase - Architecture Principles (Principle 5)\"}', 0.98, '', '2026-01-29 22:38:47'),
(6, 'Reuse With Provenance: Reuse is encouraged only when provenance, scope, and governance boundaries are preserved. Duplication is acceptable when reuse violates integrity.', '{\"document\": \"TOGAF Preliminary Phase - Architecture Principles (Principle 6)\"}', 0.90, '', '2026-01-29 22:38:48');

