(1, 'COST_001', 'Daily Mentor API Budget', 'Maximum spend on mentor APIs cannot exceed $10.00 per day across all AI operations', NULL, 'constraint', 'hard', '[\"mentor_queue_processor\", \"daily_budget_check\", \"embedding_pipeline\"]', 1, 1, '2026-02-16 23:38:10'),
(2, 'COST_002', 'Mentor Escalation Hierarchy', 'Resources must be used in order: PCDE (free) ? Lakes (free) ? Cohere ($) ? DeepSeek ($$) ? ChatGPT ($$$) ? Human (priceless)', NULL, 'directive', 'hard', '[\"mentor_queue_processor\", \"confidence_evaluator\"]', 1, 1, '2026-02-16 23:38:10'),
(3, 'COST_003', 'Mentor Response Caching', 'All mentor API responses MUST be cached to prevent repeat costs. Cache duration: Cohere (30d), DeepSeek (60d), ChatGPT (90d)', NULL, 'constraint', 'hard', '[\"cache_manager\", \"mentor_queue_processor\"]', 1, 1, '2026-02-16 23:38:10'),
(4, 'COST_004', 'Escalation Confidence Thresholds', 'Escalate to next tier only when confidence falls below: PCDE?Lakes (0.95), Lakes?Cohere (0.85), Cohere?DeepSeek (0.85), DeepSeek?ChatGPT (0.9), ChatGPT?Human (0.5)', NULL, 'directive', 'soft', '[\"confidence_evaluator\", \"mentor_queue_processor\"]', 1, 1, '2026-02-16 23:38:10'),
(5, 'COST_005', 'Budget Warning Threshold', 'When daily spend reaches 90% of budget, stop ALL non-critical mentor queries', NULL, 'constraint', 'hard', '[\"daily_budget_check\", \"mentor_queue_processor\"]', 1, 1, '2026-02-16 23:38:10'),
(6, 'COST_006', 'Human Escalation Criteria', 'Escalate to human ONLY when confidence < 0.5 AND problem is marked as \"critical\" AND all mentor tiers exhausted', NULL, 'constraint', 'hard', '[\"mentor_queue_processor\", \"hitl_escalator\"]', 1, 1, '2026-02-16 23:38:10'),
(7, 'COST_007', 'Cost Attribution', 'All mentor API costs must be attributed to the triggering procedure_id and stored in pcde_mentor_escalation_queue.actual_cost', NULL, 'directive', 'hard', '[\"mentor_queue_processor\", \"cost_tracker\"]', 1, 1, '2026-02-16 23:38:10'),
(8, 'COST_008', 'Daily Budget Reset', 'Budget counters reset at 00:00 UTC daily. No carryover of unused budget.', NULL, 'directive', 'hard', '[\"daily_budget_check\"]', 1, 1, '2026-02-16 23:38:10'),
(9, 'BUDGET_001', 'Daily Mentor Spend Limit', 'Never spend more than $10 per day on mentor APIs', NULL, 'principle', 'hard', '[\"mentor_queue_processor\", \"daily_budget_check\"]', 1, 1, '2026-02-16 23:42:03'),
(10, 'ESCALATION_001', 'Mentor Escalation Order', 'Always use resources in order: PCDE ? Lakes ? Cohere ? DeepSeek ? ChatGPT ? Human', NULL, 'principle', 'hard', '[\"mentor_queue_processor\"]', 1, 1, '2026-02-16 23:42:03'),
(11, 'CACHE_001', 'Mentor Response Caching', 'All mentor responses must be cached for at least 30 days', NULL, 'principle', 'hard', '[\"cache_manager\"]', 1, 1, '2026-02-16 23:42:03'),
(12, 'CONFIDENCE_001', 'Escalation Thresholds', 'Escalate when confidence falls below: PCDE(0.95) ? Lakes(0.85) ? Cohere(0.85) ? DeepSeek(0.9) ? ChatGPT(0.95)', NULL, 'principle', 'soft', '[\"confidence_evaluator\"]', 1, 1, '2026-02-16 23:42:03'),
(13, 'BUDGET_002', 'Budget Warning', 'Stop mentor queries at 90% of daily budget', NULL, 'principle', 'hard', '[\"daily_budget_check\"]', 1, 1, '2026-02-16 23:42:03'),
(14, 'HUMAN_001', 'Human Escalation', 'Only escalate to human when confidence < 0.5 AND problem is critical', NULL, 'principle', 'hard', '[\"mentor_queue_processor\"]', 1, 1, '2026-02-16 23:42:03');

