--
-- Structure for view `v_cost_governance_summary`
--
DROP TABLE IF EXISTS `v_cost_governance_summary`;

CREATE ALGORITHM=UNDEFINED DEFINER=`xpdgxfsp`@`localhost` SQL SECURITY DEFINER VIEW `v_cost_governance_summary`  AS SELECT `r`.`rule_code` AS `rule_code`, `r`.`rule_name` AS `rule_name`, `r`.`severity` AS `severity`, `r`.`applies_to` AS `applies_to`, count(`e`.`evaluation_id`) AS `times_applied`, max(`e`.`evaluated_at`) AS `last_applied` FROM (`igm_rules` `r` left join `igm_rule_evaluations` `e` on(`r`.`rule_id` = `e`.`rule_id`)) WHERE `r`.`rule_code` like 'COST_%' GROUP BY `r`.`rule_code`, `r`.`rule_name`, `r`.`severity`, `r`.`applies_to` ORDER BY `r`.`rule_code` ASC ;

-- --------------------------------------------------------

--
-- Structure for view `v_togaf_directive_compliance`
--
DROP TABLE IF EXISTS `v_togaf_directive_compliance`;

CREATE ALGORITHM=UNDEFINED DEFINER=`xpdgxfsp`@`localhost` SQL SECURITY DEFINER VIEW `v_togaf_directive_compliance`  AS SELECT `r`.`rule_code` AS `rule_code`, `r`.`rule_name` AS `rule_name`, count(`a`.`attestation_id`) AS `times_verified`, max(`a`.`attested_at`) AS `last_verified` FROM ((`igm_rules` `r` join `igm_rule_evaluations` `e` on(`e`.`rule_id` = `r`.`rule_id`)) join `igm_attestation_ledger` `a` on(`a`.`evaluation_id` = `e`.`evaluation_id`)) WHERE `a`.`truth_verified` = 1 GROUP BY `r`.`rule_code`, `r`.`rule_name` ;
COMMIT;

